var (
	webhookConfig WebhookConfig
	configMutex   sync.RWMutex
)

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body",
			"details": err.Error(),
		})
	}

	// Validate webhook_url field is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url field is required and cannot be empty",
		})
	}

	// Create an HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to validate the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is acceptable (2xx or 3xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook validation failed with status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	configMutex.Lock()
	webhookConfig = req
	configMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Register the ConfigureWebhook handler
	app.Post("/webhook/configure", ConfigureWebhook)

	// Health check endpoint
	app.Get("/health", func(ctx *fiber.Ctx) error {
		return ctx.JSON(fiber.Map{
			"status": "ok",
		})
	})

	// Start the server on port 3000
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

