package main

import (
	"context"
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response after configuration
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the webhook configuration endpoint
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Create a context with 3 second timeout
	timeoutCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a test request to validate the webhook URL
	req, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL: " + err.Error(),
		})
	}

	// Send the test request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Do(req)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is acceptable (2xx or 3xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook URL returned status code: " + string(rune(resp.StatusCode)),
		})
	}

	// Save the configuration (in this example, we just acknowledge it)
	// In a real application, you would save this to a database
	return ctx.Status(http.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

