// validateWebhookHost validates the webhook hostname to prevent SSRF attacks
func validateWebhookHost(hostname string) error {
	if hostname == "" {
		return fmt.Errorf("hostname is empty")
	}

	// Resolve the hostname to IP address
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return fmt.Errorf("hostname does not resolve to any IP address")
	}

	// Check for private/reserved IP addresses
	for _, ip := range ips {
		if isPrivateOrReservedIP(ip) {
			return fmt.Errorf("webhook URL cannot point to private or reserved IP address: %s", ip.String())
		}
	}

	return nil
}

// isPrivateOrReservedIP checks if an IP address is private or reserved
func isPrivateOrReservedIP(ip net.IP) bool {
	// Check for localhost
	if ip.IsLoopback() {
		return true
	}

	// Check for private IP ranges
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for multicast
	if ip.IsMulticast() {
		return true
	}

	// Check for unspecified address
	if ip.IsUnspecified() {
		return true
	}

	return false
}

