			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Validate the webhook URL by sending a test GET request
