		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}

	// Save the configuration (in a real application, this would be persisted to a database)
	// For this example, we'll just acknowledge the successful configuration
	return ctx.Status(http.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     req.WebhookURL,
	})
}

// validateWebhookURL sends a test GET request to the webhook URL with a 3-second timeout
func validateWebhookURL(webhookURL string) error {
	// Create a context with a 3-second timeout
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new HTTP request with the context
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, webhookURL, nil)
	if err != nil {
		return err
	}

	// Send the request
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	// Check if the response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fiber.NewError(resp.StatusCode, "webhook returned non-2xx status code")
	}

	return nil
}

