	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isPublicIP checks if the given hostname resolves to a public IP address
// Returns false for private/internal IPs to prevent SSRF attacks
func isPublicIP(hostname string) bool {
	if hostname == "" {
		return false
	}

	// Reject localhost and common local hostnames
	switch hostname {
	case "localhost", "127.0.0.1", "::1", "0.0.0.0":
		return false
	}

	// Resolve hostname to IP address
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return false
	}

	for _, ip := range ips {
		// Check if IP is private or reserved
		if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || 
		   ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
			return false
		}
	}

	return len(ips) > 0
}

