	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response to the webhook configuration
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the request body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body",
		})
	}

	// Validate webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate webhook URL format
	if _, err := url.ParseRequestURI(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL format",
		})
	}

	// Send a test request to validate the webhook
	if err := validateWebhook(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook: " + err.Error(),
		})
	}

	// Save the configuration (in a real application, this would save to a database)
	// For this example, we'll just return success
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

// validateWebhook sends a test GET request to the webhook URL with a 3-second timeout
func validateWebhook(webhookURL string) error {
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(webhookURL)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	// Accept any successful HTTP response (2xx status codes)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fiber.NewError(fiber.StatusBadRequest, "webhook returned non-2xx status code")
	}

	return nil
}

func main() {
	app := fiber.New()

	// Configure the webhook endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Health check endpoint
	app.Get("/health", func(ctx *fiber.Ctx) error {
		return ctx.JSON(map[string]string{"status": "ok"})
	})

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

