// isPrivateIP checks if an IP address is private or reserved
func isPrivateIP(ip net.IP) bool {
	// Check for private and reserved IP ranges
	return ip.IsLoopback() ||
		ip.IsPrivate() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsMulticast() ||
		ip.IsUnspecified()
}

// validateWebhookURL validates the webhook URL for security concerns
func validateWebhookURL(urlStr string) error {
	parsedURL, err := url.ParseRequestURI(urlStr)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("invalid scheme")
	}

	// Validate hostname to prevent SSRF attacks
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid hostname")
	}

	// Resolve the hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	if len(ips) == 0 {
		return fmt.Errorf("no IP addresses found for hostname")
	}

	// Check if any resolved IP is private/reserved
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL resolves to a private or reserved IP address")
		}
	}

	return nil
}

