)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response to the webhook configuration request
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles POST requests to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON format",
		})
	}

	// Validate webhook URL
	if config.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format
	if _, err := url.ParseRequestURI(config.WebhookURL); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL format",
		})
	}

	// Send test request to validate the webhook
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is acceptable (2xx or 3xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook validation failed with status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration (in a real application, this would be saved to a database)
	// For this example, we'll just return success
	return ctx.Status(http.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: fmt.Sprintf("Webhook configured successfully: %s", config.WebhookURL),
	})
}

func main() {
	app := fiber.New()

	// Configure the webhook endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Health check endpoint
	app.Get("/health", func(ctx *fiber.Ctx) error {
		return ctx.JSON(map[string]string{
			"status": "ok",
		})
	})

	// Start the server on port 3000
	if err := app.Listen(":3000"); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

