// validateWebhookHost validates the webhook hostname to prevent SSRF attacks
func validateWebhookHost(hostname string) error {
	if hostname == "" {
		return fmt.Errorf("empty hostname")
	}

	// Resolve the hostname to IP address
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return fmt.Errorf("hostname did not resolve to any IP address")
	}

	// Check if the resolved IP is in a private/reserved range
	for _, ip := range ips {
		if isPrivateOrReservedIP(ip) {
			return fmt.Errorf("webhook URL resolves to a private or reserved IP address")
		}
	}

	return nil
}

// isPrivateOrReservedIP checks if an IP address is in a private or reserved range
func isPrivateOrReservedIP(ip net.IP) bool {
	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check for private ranges
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for multicast
	if ip.IsMulticast() {
		return true
	}

	// Check for unspecified
	if ip.IsUnspecified() {
		return true
	}

	return false
}

