import (
	"context"
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response from the handler
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	URL     string `json:"url,omitempty"`
}

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate webhook URL is not empty
	if config.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create a context with 3-second timeout for the test request
	testCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new HTTP request with the context
	req, err := http.NewRequestWithContext(testCtx, http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL: " + err.Error(),
		})
	}

	// Send the test request
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return ctx.Status(http.StatusBadGateway).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is acceptable (2xx or 3xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(http.StatusBadGateway).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook URL returned status code: " + resp.Status,
		})
	}

	// Save the configuration (in a real application, this would be saved to a database)
	// For this example, we'll just confirm the configuration was saved
	return ctx.Status(http.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     config.WebhookURL,
	})
}

// main sets up the Fiber app and routes
func main() {
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

