package main

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response to the webhook configuration
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse the JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook URL is provided
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// Validate webhook URL format
	if _, err := url.ParseRequestURI(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid webhook URL format",
		})
	}

	// Send test request to validate webhook
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook: %v", err),
		})
	}
	defer resp.Body.Close()

	// Read response body to ensure we got a valid response
	_, err = io.ReadAll(resp.Body)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to read webhook response: %v", err),
		})
	}

	// Check if the webhook returned a successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook returned status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration (in a real application, this would be saved to a database)
	// For this example, we'll just return success
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: fmt.Sprintf("Webhook configured successfully: %s", config.WebhookURL),
	})
}

func main() {
	app := fiber.New()

	// Configure webhook endpoint
	app.Post("/webhook/configure", ConfigureWebhook)

	// Health check endpoint
	app.Get("/health", func(ctx *fiber.Ctx) error {
		return ctx.JSON(fiber.Map{"status": "ok"})
	})

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

